SELECT MAX(email_id) AS highest_email_id
FROM emails
WHERE is_deleted = 0 AND priority = 'high';

SELECT email_id, subject, from_email, is_read, COUNT(*) OVER () AS total_emails
FROM emails
WHERE is_deleted = 0 AND email_type = 'external';

SELECT open_rate
FROM email_open_rates
WHERE open_rate_id = 1;
